import React, { createContext, useState, useEffect } from 'react';
import axios from 'axios';

// Create context
const AuthContext = createContext();

export const AuthProvider = ({ children }) => {
  const [user, setUser] = useState(null);
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);

  // Check if user is logged in on initial load
  useEffect(() => {
    const checkLoggedIn = async () => {
      // Check if token exists in local storage
      const token = localStorage.getItem('token');

      if (token) {
        // Set auth token header
        setAuthToken(token);

        try {
          // Verify token by getting user data
          const res = await axios.get('/api/users/profile/');
          setUser(res.data);
          setIsAuthenticated(true);
        } catch (err) {
          // Token is invalid
          localStorage.removeItem('token');
          setAuthToken(null);
          setUser(null);
          setIsAuthenticated(false);
          setError('Session expired. Please log in again.');
        }
      }

      setLoading(false);
    };

    checkLoggedIn();
  }, []);

  // Set auth token for axios
  const setAuthToken = (token) => {
    if (token) {
      axios.defaults.headers.common['Authorization'] = `Bearer ${token}`;
    } else {
      delete axios.defaults.headers.common['Authorization'];
    }
  };

  // Register user - Version simplifiée
  const register = async (userData) => {
    try {
      console.log('Tentative d\'inscription avec:', userData);
      setError(null);

      // URL directe sans préfixe /api
      const res = await axios.post('/users/register/', {
        username: userData.username,
        email: userData.email,
        password: userData.password,
        password2: userData.password2,
        bio: userData.bio || ''
      });

      console.log('Réponse d\'inscription:', res.data);
      alert('Inscription réussie!');
      window.location.href = '/login';
      return res.data;
    } catch (err) {
      console.error('Erreur d\'inscription:', err);
      let message = 'L\'inscription a échoué';

      if (err.response?.data) {
        if (typeof err.response.data === 'object') {
          // Simplifier le message d'erreur
          message = Object.keys(err.response.data)
            .map(key => `${key}: ${err.response.data[key]}`)
            .join(', ');
        } else {
          message = err.response.data;
        }
      }

      setError(message);
      alert('Erreur: ' + message);
    }
  };

  // Login user
  const login = async (userData) => {
    try {
      console.log('Tentative de connexion avec:', userData);
      setError(null); // Effacer les erreurs précédentes

      // Utiliser le chemin correct pour l'API
      const res = await axios.post('/api/token/', {
        email: userData.email,
        password: userData.password
      });

      console.log('Réponse de connexion:', res.data);

      // Save token to local storage
      localStorage.setItem('token', res.data.access);

      // Set auth token in headers
      setAuthToken(res.data.access);

      try {
        // Get user data
        // Utiliser le chemin correct pour l'API
        const userRes = await axios.get('/api/users/profile/');
        console.log('Données utilisateur:', userRes.data);
        setUser(userRes.data);
        setIsAuthenticated(true);
        setError(null);

        // Afficher un message de succès
        alert(`Connexion réussie! Bienvenue, ${userRes.data.username}.`);

        // Rediriger vers la page d'accueil
        window.location.href = '/';
      } catch (profileErr) {
        console.error('Erreur lors de la récupération du profil:', profileErr);
        // Même si nous ne pouvons pas récupérer le profil, l'utilisateur est authentifié
        setIsAuthenticated(true);
        alert('Connexion réussie, mais impossible de récupérer votre profil.');
        window.location.href = '/';
      }

      return res.data;
    } catch (err) {
      console.error('Erreur de connexion complète:', err);
      console.error('Détails de la réponse:', err.response);

      let errorMsg = 'Échec de connexion. Vérifiez vos identifiants.';

      if (err.response?.data) {
        if (typeof err.response.data === 'object') {
          if (err.response.data.detail) {
            errorMsg = err.response.data.detail;
          } else {
            // Construire un message d'erreur à partir de l'objet
            try {
              errorMsg = Object.entries(err.response.data)
                .map(([key, value]) => `${key}: ${Array.isArray(value) ? value.join(', ') : value}`)
                .join('. ');
            } catch (e) {
              console.error('Erreur lors du traitement des erreurs:', e);
            }
          }
        } else if (typeof err.response.data === 'string') {
          errorMsg = err.response.data;
        }
      } else if (err.message) {
        errorMsg = err.message;
      }

      setError(errorMsg);
      alert('Erreur de connexion: ' + errorMsg);
    }
  };

  // Logout user
  const logout = () => {
    // Remove token from local storage
    localStorage.removeItem('token');

    // Remove auth token from headers
    setAuthToken(null);

    // Reset state
    setUser(null);
    setIsAuthenticated(false);
  };

  // Update user profile
  const updateProfile = async (userData) => {
    try {
      const res = await axios.put('/users/me/', userData);
      setUser(res.data);
      return res.data;
    } catch (err) {
      setError(err.response?.data?.detail || 'Profile update failed');
      throw err;
    }
  };

  // Clear errors
  const clearError = () => {
    setError(null);
  };

  return (
    <AuthContext.Provider
      value={{
        user,
        isAuthenticated,
        loading,
        error,
        register,
        login,
        logout,
        updateProfile,
        clearError
      }}
    >
      {children}
    </AuthContext.Provider>
  );
};

// Export context for use in components
AuthContext.displayName = 'AuthContext';
AuthProvider.context = AuthContext;
export default AuthContext;
